/**
 * Generated by `createservice miniapp.ChangeOIDCClientService`
 */

const { GQLError, GQLErrorCode: { BAD_USER_INPUT } } = require('@open-condo/keystone/errors')
const { GQLCustomSchema, getByCondition } = require('@open-condo/keystone/schema')

const { productionClient, developmentClient } = require('@dev-portal-api/domains/common/utils/serverClients')
const { CondoB2BAppGql, CondoB2CAppGql, CondoOIDCClientGql } = require('@dev-portal-api/domains/condo/gql')
const access = require('@dev-portal-api/domains/miniapp/access/ChangeOIDCClientService')
const { OIDC_CLIENT_NOT_FOUND, APP_NOT_FOUND } = require('@dev-portal-api/domains/miniapp/constants/errors')
const { PROD_ENVIRONMENT } = require('@dev-portal-api/domains/miniapp/constants/publishing')
const { getAllOIDCClients, B2BApp, B2CApp } = require('@dev-portal-api/domains/miniapp/utils/serverSchema')
const { formatOIDCClient } = require('@dev-portal-api/domains/miniapp/utils/serverSchema/oidcClient')


const ERRORS = {
    APP_NOT_FOUND: {
        code: BAD_USER_INPUT,
        type: APP_NOT_FOUND,
        message: 'The specified app was not found',
        messageForUser: 'api.miniapp.APP_NOT_FOUND',
    },
    OIDC_CLIENT_NOT_FOUND: {
        code: BAD_USER_INPUT,
        type: OIDC_CLIENT_NOT_FOUND,
        message: 'The specified OIDC client was not found among clients available to this app',
        messageForUser: 'api.miniapp.OIDC_CLIENT_NOT_FOUND',
    },
}

const ChangeOIDCClientService = new GQLCustomSchema('ChangeOIDCClientService', {
    types: [
        {
            access: true,
            type: 'input ChangeOIDCClientInput { dv: Int!, sender: SenderFieldInput!, app: AppWhereUniqueInput!, environment: AppEnvironment!, oidcClientId: String! }',
        },
    ],

    mutations: [
        {
            access: access.canChangeOIDCClient,
            schema: 'changeOIDCClient(data: ChangeOIDCClientInput!): OIDCClient',
            resolver: async (parent, args, context) => {
                const { data: { app, environment, dv, sender, oidcClientId } } = args

                const serverClient = environment === PROD_ENVIRONMENT
                    ? productionClient
                    : developmentClient

                const exportIdField = `${environment}ExportId`
                const oidcClientIdField = `${environment}OidcClientId`

                // Validate: clientId must reference a real OIDC client
                // Admin/support bypass ownership check; regular users are restricted to their own clients
                let matched
                const user = context.authedItem
                if (user.isAdmin || user.isSupport) {
                    const [found] = await serverClient.getModels({
                        modelGql: CondoOIDCClientGql,
                        where: { id: oidcClientId, deletedAt: null },
                        first: 1,
                    })
                    matched = found ? formatOIDCClient(found) : null
                } else {
                    const allClients = await getAllOIDCClients(context, { environment })
                    matched = allClients && allClients.find(c => c.id === oidcClientId)
                }
                if (!matched) {
                    throw new GQLError(ERRORS.OIDC_CLIENT_NOT_FOUND, context)
                }

                // Resolve local app (B2B or B2C)
                const [b2bApp, b2cApp] = await Promise.all([
                    getByCondition('B2BApp', { id: app.id, deletedAt: null }),
                    getByCondition('B2CApp', { id: app.id, deletedAt: null }),
                ])
                const localApp = b2bApp || b2cApp
                if (!localApp) {
                    throw new GQLError(ERRORS.APP_NOT_FOUND, context)
                }

                const condoAppGql = b2bApp ? CondoB2BAppGql : CondoB2CAppGql

                // Persist to dev-portal local app
                const Model = b2bApp ? B2BApp : B2CApp
                await Model.update(context, localApp.id, {
                    dv,
                    sender,
                    [oidcClientIdField]: oidcClientId,
                })

                // If app is published, also update the condoApp link
                const exportId = localApp[exportIdField]
                if (exportId) {
                    const condoApp = await serverClient.findExportedModel({
                        modelGql: condoAppGql,
                        exportId,
                        id: app.id,
                    })
                    if (condoApp) {
                        await serverClient.updateModel({
                            modelGql: condoAppGql,
                            id: condoApp.id,
                            updateInput: {
                                dv,
                                sender,
                                oidcClient: { connect: { id: oidcClientId } },
                            },
                        })
                    }
                }

                return matched
            },
        },
    ],

})

module.exports = {
    ChangeOIDCClientService,
}
